const payload = $json;
const allowedAbas = ['dados_gerais','requisitos','cronograma'];
if (!payload.aba || !allowedAbas.includes(payload.aba)) {
  throw new Error('Campo `aba` inválido. Use: dados_gerais, requisitos ou cronograma.');
}
if (!payload.texto_base || String(payload.texto_base).trim().length < 10) {
  throw new Error('Campo `texto_base` obrigatório com pelo menos 10 caracteres.');
}
if (String(payload.texto_base).length > 12000) {
  throw new Error('Campo `texto_base` excede limite de 12000 caracteres.');
}
return [{ json: payload }];

const cfg = {
  descricao_projeto: { prompt_template_id: 'dados_gerais.descricao_projeto.v1', output_key: 'descricao_projeto' },
  situacao_atual: { prompt_template_id: 'dados_gerais.situacao_atual.v1', output_key: 'situacao_atual' },
  aprovacoes_anteriores: { prompt_template_id: 'dados_gerais.aprovacoes_anteriores.v1', output_key: 'aprovacoes_anteriores' },
  escopo_projeto: { prompt_template_id: 'dados_gerais.escopo_projeto.v1', output_key: 'escopo_projeto' },
  fora_escopo: { prompt_template_id: 'dados_gerais.fora_escopo.v1', output_key: 'fora_escopo' },
  alternativas_avaliadas: { prompt_template_id: 'dados_gerais.alternativas_avaliadas.v1', output_key: 'alternativas_avaliadas' },
  riscos_mitigacao: { prompt_template_id: 'dados_gerais.riscos_mitigacao.v1', output_key: 'riscos_mitigacao' },
  resultados_qualitativos: { prompt_template_id: 'dados_gerais.resultados_qualitativos.v1', output_key: 'resultados_qualitativos' },
  ganhos_potenciais: { prompt_template_id: 'dados_gerais.ganhos_potenciais.v1', output_key: 'ganhos_potenciais' },
  ganhos_reais: { prompt_template_id: 'dados_gerais.ganhos_reais.v1', output_key: 'ganhos_reais' },
  notas_orcamento: { prompt_template_id: 'dados_gerais.notas_orcamento.v1', output_key: 'notas_orcamento' },
  analise_financeira: { prompt_template_id: 'dados_gerais.analise_financeira.v1', output_key: 'analise_financeira' },
};

if (!cfg[$json.campo]) {
  throw new Error('Campo de dados_gerais inválido.');
}

return [{
  json: {
    ...$json,
    ia_request: {
      prompt_template_id: cfg[$json.campo].prompt_template_id,
      input: $json.texto_base,
      output_key: cfg[$json.campo].output_key,
      metadata: { proposal_id: $json.proposal_id || null, aba: $json.aba, campo: $json.campo || null }
    }
  }
}];

const hasReq = Array.isArray($json.requisitos) && $json.requisitos.length > 0;
return [{
  json: {
    ...$json,
    ia_request: {
      prompt_template_id: hasReq ? 'requisitos.com_lista.v1' : 'requisitos.sem_lista.v1',
      input: $json.texto_base,
      context: { requisitos: $json.requisitos || [] },
      output_key: 'levantamento_requisitos',
      metadata: { proposal_id: $json.proposal_id || null, aba: $json.aba }
    }
  }
}];

const hasAcoes = Array.isArray($json.acoes) && $json.acoes.length > 0;
return [{
  json: {
    ...$json,
    ia_request: {
      prompt_template_id: hasAcoes ? 'cronograma.com_acoes.v1' : 'cronograma.sem_acoes.v1',
      input: $json.texto_base,
      context: { acoes: $json.acoes || [] },
      output_key: 'cronograma',
      metadata: { proposal_id: $json.proposal_id || null, aba: $json.aba }
    }
  }
}];

const raw = $json.text || $json.response || $json.data || '';
if (!raw) throw new Error('Resposta vazia da IA.');
let parsed = raw;
if (typeof raw === 'string') {
  const cleaned = raw.replace(/```json|```/g, '').trim();
  try { parsed = JSON.parse(cleaned); } catch { parsed = { texto: cleaned }; }
}
return [{ json: { sucesso: true, resultado: parsed } }];
